const raw = $input.first().json.data || '';
const sourceUrl = 'https://psl.noaa.gov/data/correlation/oni.data';
function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'monthly');
const expectedFreshnessHours = 24 * 35;
const isFresh = (new Date() - new Date(now)) / 3600000 < expectedFreshnessHours;

const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const rows = [];
for (const line of raw.split(/\r?\n/)) {
  const parts = line.trim().split(/\s+/);
  if (parts.length < 13) continue;

  const year = Number(parts[0]);
  if (!Number.isInteger(year) || year < 1950) continue;

  for (let i = 0; i < months.length; i++) {
    const value = Number(parts[i + 1]);
    if (Number.isNaN(value) || value < -10) continue;

    rows.push({
      year,
      month: months[i],
      month_number: i + 1,
      period: `${year}-${String(i + 1).padStart(2, '0')}`,
      period_label: `${year}-${months[i]}`,
      oni_value: Number(value.toFixed(2))
    });
  }
}

if (!rows.length) {
  throw new Error('No valid ONI values parsed from NOAA ENSO file');
}

const latest = rows[rows.length - 1];
const recentSeries = rows.slice(-6);

let ensoPhase = 'NEUTRAL';
let phaseStrength = 'neutral';
let alertLevel = 'LOW';
let impactForecast = 'No major ENSO-driven climate disruptions expected.';
let northNortheastImpact = 'No strong ENSO-driven anomaly signaled.';
let southImpact = 'No strong ENSO-driven anomaly signaled.';
let summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating a neutral ENSO phase. No major ENSO-driven climate disruption is currently signaled for Brazil.`;
let signals = [
  'ENSO phase neutral',
  `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
  'No major ENSO-driven disruption signaled for Brazil'
];

if (latest.oni_value >= 0.5) {
  ensoPhase = 'EL_NINO';
  alertLevel = 'MODERATE';
  phaseStrength = 'moderate';
  impactForecast = 'Possible water shortages in North and Northeast Brazil; increased rainfall in Southern Brazil.';
  northNortheastImpact = 'Drier and hotter conditions with higher drought and wildfire risk.';
  southImpact = 'Wetter conditions with higher heavy-rain and flooding risk.';
  summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating El Nino conditions. Brazil faces higher drought pressure in North and Northeast regions and higher rainfall risk in the South.`;
  signals = [
    'ENSO phase El Nino',
    `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
    'North and Northeast Brazil drought risk elevated',
    'Southern Brazil heavy rainfall risk elevated'
  ];

  if (latest.oni_value >= 1.5) {
    alertLevel = 'CRITICAL';
    phaseStrength = 'strong';
    impactForecast = 'High risk of drought in Amazon and Northeast Brazil; severe flood risk in Southern Brazil.';
    northNortheastImpact = 'Strong drought and wildfire pressure across Amazon and Northeast Brazil.';
    southImpact = 'Strong heavy-rain and flood pressure in Southern Brazil.';
    summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating a strong El Nino phase. Brazil faces severe drought pressure in Amazon and Northeast regions and severe flood risk in the South.`;
    signals = [
      'ENSO phase strong El Nino',
      `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
      'Amazon and Northeast Brazil drought risk critical',
      'Southern Brazil flood risk critical'
    ];
  }
} else if (latest.oni_value <= -0.5) {
  ensoPhase = 'LA_NINA';
  alertLevel = 'MODERATE';
  phaseStrength = 'moderate';
  impactForecast = 'Drier conditions likely in Southern Brazil; wetter conditions in North and Northeast Brazil.';
  northNortheastImpact = 'Wetter conditions with higher river flooding risk.';
  southImpact = 'Drier conditions with higher agricultural drought risk.';
  summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating La Nina conditions. Brazil faces higher dryness risk in the South and wetter conditions in North and Northeast regions.`;
  signals = [
    'ENSO phase La Nina',
    `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
    'Southern Brazil drought risk elevated',
    'North and Northeast Brazil flood risk elevated'
  ];

  if (latest.oni_value <= -1.5) {
    alertLevel = 'CRITICAL';
    phaseStrength = 'strong';
    impactForecast = 'High risk of drought in Southern Brazil crops; flood risk in North and Northeast Brazil.';
    northNortheastImpact = 'Strong wet conditions with flood pressure in North and Northeast Brazil.';
    southImpact = 'Strong agricultural drought pressure in Southern Brazil.';
    summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating a strong La Nina phase. Brazil faces critical southern dryness pressure and elevated flood risk in North and Northeast regions.`;
    signals = [
      'ENSO phase strong La Nina',
      `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
      'Southern Brazil crop drought risk critical',
      'North and Northeast Brazil flood risk elevated'
    ];
  }
}

return [{
  json: {
    source: 'NOAA_ENSO',
    source_url: sourceUrl,
    country: 'BR',
    macroarea: 'environment',
    collected_at: now,
    collected_period: _collectedPeriod,
        is_fresh: isFresh,
    latest_period: latest.period,
    latest_period_label: latest.period_label,
    latest_year: latest.year,
    latest_month: latest.month,
    latest_month_number: latest.month_number,
    oni_value: latest.oni_value,
    enso_phase: ensoPhase,
    phase_strength: phaseStrength,
    alert_level: alertLevel,
    impact_forecast: impactForecast,
    brazil_impact_north_northeast: northNortheastImpact,
    brazil_impact_south: southImpact,
    summary_en: summaryEn,
    signals,
    history_window_months: recentSeries.length,
    recent_series: recentSeries,
    _chart_fields: ["recent_series"]
  }
}];

const now = new Date().toISOString();
const meta = $('NOAA Parse Signals').item.json;

return [{
  json: {
    source: 'NOAA_ENSO',
    country: 'BR',
    macroarea: 'environment',
    cadenza: 'monthly',
    run_date: now,
    status: 'done',
    completed_at: now,
    latest_period: meta.latest_period || null,
    enso_phase: meta.enso_phase || null,
  },
}];

const raw = ($json.text || '').trim();
const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
const parsed = JSON.parse(cleaned);
const base = $('NOAA ENSO Parse').item.json;

return [{ json: {
  ...base,
  rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
  rule_based_movement_label: base.movement_label || 'mixed',
  fallback_summary_en: base.summary_en || '',
  movement_label: parsed.movement_label || base.movement_label || 'mixed',
  signals: Array.isArray(parsed.signals) && parsed.signals.length ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
  summary_en: parsed.summary_en || base.summary_en || ''
}}];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '11_NOAA_ENSO',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json }];
